package cn.mtplayer.tv;
import android.app.AlertDialog;import android.content.Intent;import android.os.Bundle;import android.os.Handler;import android.os.Looper;import android.view.Gravity;import android.view.View;import android.view.ViewGroup;import android.widget.Button;import android.widget.EditText;import android.widget.FrameLayout;import android.widget.HorizontalScrollView;import android.widget.ImageView;import android.widget.LinearLayout;import android.widget.ScrollView;import android.widget.TextView;import android.widget.Toast;import androidx.appcompat.app.AppCompatActivity;import androidx.media3.common.util.UnstableApi;import androidx.recyclerview.widget.GridLayoutManager;import androidx.recyclerview.widget.LinearLayoutManager;import androidx.recyclerview.widget.RecyclerView;import com.bumptech.glide.Glide;import java.util.ArrayList;import java.util.List;import java.util.Locale;import java.util.concurrent.ExecutorService;import java.util.concurrent.Executors;import cn.mtplayer.core.account.AccountClient;import cn.mtplayer.core.config.SourceGroup;import cn.mtplayer.core.model.LiveChannel;import cn.mtplayer.core.model.MediaItem;import cn.mtplayer.core.model.Site;
import cn.mtplayer.core.sync.AndroidSyncService;

@UnstableApi public final class TvMainActivity extends AppCompatActivity{
private final ExecutorService executor=Executors.newFixedThreadPool(4);private final Handler handler=new Handler(Looper.getMainLooper());private FrameLayout content;private TvLibrary library;private List<Site> sites=new ArrayList<>();
@Override protected void onCreate(Bundle b){super.onCreate(b);library=TvServices.library;setContentView(shell());showHome();}@Override protected void onDestroy(){executor.shutdownNow();handler.removeCallbacksAndMessages(null);super.onDestroy();}
private View shell(){LinearLayout root=new LinearLayout(this);root.setOrientation(LinearLayout.HORIZONTAL);root.setBackgroundColor(TvUi.BG);LinearLayout rail=new LinearLayout(this);rail.setOrientation(LinearLayout.VERTICAL);rail.setPadding(TvUi.dp(this,20),TvUi.dp(this,24),TvUi.dp(this,20),TvUi.dp(this,20));rail.setBackgroundColor(TvUi.SURFACE);ImageView logo=new ImageView(this);logo.setScaleType(ImageView.ScaleType.CENTER_INSIDE);Glide.with(this).load(R.drawable.logo_header).into(logo);rail.addView(logo,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,TvUi.dp(this,100)));String[] names={"首页","搜索","我的收藏","观看记录","直播频道","账户与同步","设置","关于软件"};Runnable[] actions={this::showHome,this::showSearch,()->showLibrary(true),()->showLibrary(false),this::showLive,this::showAccount,this::showSettings,this::showAbout};for(int i=0;i<names.length;i++){Button v=TvUi.button(this,names[i],false);int x=i;v.setOnClickListener(q->actions[x].run());rail.addView(v,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,TvUi.dp(this,58)));}root.addView(rail,new LinearLayout.LayoutParams(TvUi.dp(this,250),ViewGroup.LayoutParams.MATCH_PARENT));content=new FrameLayout(this);root.addView(content,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.MATCH_PARENT,1));return root;}
private LinearLayout page(String eyebrow,String title){LinearLayout r=TvUi.column(this);TextView e=TvUi.text(this,eyebrow);e.setTextColor(TvUi.RED);r.addView(e,TvUi.matchWrap());r.addView(TvUi.title(this,title,34),TvUi.matchWrap());return r;}private void setPage(View v){content.removeAllViews();content.addView(v,new FrameLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.MATCH_PARENT));}
private void showHome(){ScrollView scroll=new ScrollView(this);LinearLayout root=page("MT 精选","热门片单");TextView status=TvUi.text(this,"正在读取配置源…");root.addView(status,TvUi.matchWrap());scroll.addView(root);setPage(scroll);executor.execute(()->{try{sites=TvServices.configurations.enabledSites();if(sites.isEmpty()){runOnUiThread(()->status.setText("暂无配置源，请在设置中添加 HTTP 或 HTTPS 配置地址。"));return;}List<MediaItem> values=TvServices.catalogue.latest(sites,60);runOnUiThread(()->{status.setText("已启用 "+sites.size()+" 个可用接口");addRows(root,values);});}catch(Exception e){runOnUiThread(()->status.setText("读取失败："+msg(e)));}});}
private void addRows(LinearLayout root,List<MediaItem> items){String[][] cats={{"电影 Top 10","电影"},{"电视剧 Top 10","电视|剧"},{"动漫电影 Top 10","动漫|动画"},{"动漫番剧 Top 10","番剧|动漫"},{"综艺 Top 10","综艺"}};for(String[] c:cats){List<MediaItem> v=new ArrayList<>();for(MediaItem i:items){String k=(safe(i.type)+safe(i.name)).toLowerCase(Locale.ROOT);if(k.matches(".*("+c[1]+").*"))v.add(i);if(v.size()==10)break;}if(v.isEmpty())v.addAll(items.subList(0,Math.min(10,items.size())));root.addView(TvUi.title(this,c[0],24),TvUi.matchWrap());RecyclerView row=new RecyclerView(this);row.setLayoutManager(new LinearLayoutManager(this,RecyclerView.HORIZONTAL,false));row.setAdapter(new TvMediaAdapter(v,this::open));root.addView(row,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,TvUi.dp(this,355)));}}
private void showSearch(){LinearLayout root=page("全接口聚合","搜索影片");LinearLayout bar=new LinearLayout(this);EditText input=TvUi.input(this,"输入片名");Button go=TvUi.button(this,"搜索",true);bar.addView(input,new LinearLayout.LayoutParams(0,TvUi.dp(this,62),1));bar.addView(go,new LinearLayout.LayoutParams(TvUi.dp(this,120),TvUi.dp(this,62)));root.addView(bar,TvUi.matchWrap());TextView status=TvUi.text(this,"遥控器确认键开始搜索；只显示接口实际返回的影片。");root.addView(status,TvUi.matchWrap());RecyclerView list=new RecyclerView(this);list.setLayoutManager(new GridLayoutManager(this,5));root.addView(list,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,0,1));setPage(root);go.setOnClickListener(v->{String q=input.getText().toString().trim();if(q.isEmpty())return;status.setText("正在并发搜索…");executor.execute(()->{try{if(sites.isEmpty())sites=TvServices.configurations.enabledSites();List<MediaItem> found=TvServices.catalogue.searchAll(sites,q);runOnUiThread(()->{status.setText(found.isEmpty()?"没有找到影片":"找到 "+found.size()+" 个接口结果");list.setAdapter(new TvMediaAdapter(found,this::open));if(list.getChildCount()>0)list.getChildAt(0).requestFocus();});}catch(Exception e){runOnUiThread(()->status.setText("搜索失败："+msg(e)));}});});}
private void showLibrary(boolean fav){LinearLayout root=page("本地保存",fav?"我的收藏":"观看记录");List<MediaItem> values=fav?library.favorites():library.history();root.addView(TvUi.text(this,values.isEmpty()?"暂无内容；退出登录不会清除本地数据。":"共 "+values.size()+" 条"),TvUi.matchWrap());RecyclerView list=new RecyclerView(this);list.setLayoutManager(new GridLayoutManager(this,5));list.setAdapter(new TvMediaAdapter(values,this::open));root.addView(list,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,0,1));setPage(root);}
private void showLive(){ScrollView scroll=new ScrollView(this);LinearLayout root=page("LIVE & M3U8","直播频道");root.addView(TvUi.text(this,"已启用配置中的直播源会自动识别，也可手动输入直播流地址。"),TvUi.matchWrap());EditText url=TvUi.input(this,"http:// 或 https://.../live.m3u8");Button play=TvUi.button(this,"添加并播放",true);root.addView(url,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,TvUi.dp(this,64)));root.addView(play,new LinearLayout.LayoutParams(TvUi.dp(this,260),TvUi.dp(this,62)));play.setOnClickListener(v->playLive(url.getText().toString().trim(),"直播频道"));TextView status=TvUi.text(this,"正在读取配置中的直播频道…");root.addView(status,TvUi.matchWrap());LinearLayout channels=new LinearLayout(this);channels.setOrientation(LinearLayout.VERTICAL);root.addView(channels,TvUi.matchWrap());scroll.addView(root);setPage(scroll);executor.execute(()->{try{List<LiveChannel> values=TvServices.configurations.enabledLiveChannels();runOnUiThread(()->{status.setText(values.isEmpty()?"配置中没有读取到可用直播频道。":"共识别 "+values.size()+" 个直播频道，点击即可播放。");for(LiveChannel channel:values){Button button=TvUi.button(this,(channel.group==null||channel.group.isEmpty()?"":channel.group+" · ")+channel.name,false);button.setOnClickListener(v->playLive(channel.url,channel.name));channels.addView(button,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,TvUi.dp(this,62)));}});}catch(Exception ex){runOnUiThread(()->status.setText("直播源读取失败："+msg(ex)));}});}
private void playLive(String value,String title){if(!isHttpAddress(value)){toast("请输入有效的 HTTP 或 HTTPS 直播地址");return;}Intent i=new Intent(this,TvPlayerActivity.class);i.putExtra("url",value);i.putExtra("title",title);startActivity(i);}
private void showSettings(){ScrollView scroll=new ScrollView(this);LinearLayout root=page("数据来源","配置源管理");Button add=TvUi.button(this,"＋ 添加配置源",true);root.addView(add,new LinearLayout.LayoutParams(TvUi.dp(this,280),TvUi.dp(this,62)));for(SourceGroup g:TvServices.configurations.groups()){LinearLayout row=new LinearLayout(this);Button toggle=TvUi.button(this,(g.enabled?"✓ ":"○ ")+g.name,false),remove=TvUi.button(this,"删除",false);toggle.setOnClickListener(v->{TvServices.configurations.setEnabled(g.id,!g.enabled);showSettings();});remove.setOnClickListener(v->{TvServices.configurations.remove(g.id);showSettings();});row.addView(toggle,new LinearLayout.LayoutParams(0,TvUi.dp(this,60),1));row.addView(remove,new LinearLayout.LayoutParams(TvUi.dp(this,110),TvUi.dp(this,60)));root.addView(row,TvUi.matchWrap());root.addView(TvUi.text(this,g.url),TvUi.matchWrap());}root.addView(TvUi.title(this,"Spider Gateway",22),TvUi.matchWrap());Button gateway=TvUi.button(this,TvServices.spiderGateway.isEnabled()?"关闭局域网 Gateway":"启用局域网 Gateway",TvServices.spiderGateway.isEnabled());root.addView(gateway,new LinearLayout.LayoutParams(TvUi.dp(this,320),TvUi.dp(this,62)));root.addView(TvUi.text(this,"供 Windows/Web 调用 Android CSP 插件。端口："+TvServices.spiderGateway.port()+"\n令牌："+TvServices.spiderGateway.token()+"\n仅在可信局域网使用。"),TvUi.matchWrap());gateway.setOnClickListener(v->{try{TvServices.spiderGateway.setEnabled(!TvServices.spiderGateway.isEnabled());showSettings();}catch(Exception e){toast(msg(e));}});add.setOnClickListener(v->sourceDialog());scroll.addView(root);setPage(scroll);}
private void sourceDialog(){LinearLayout f=TvUi.column(this);EditText n=TvUi.input(this,"配置源名称"),u=TvUi.input(this,"http:// 或 https:// 配置接口");f.addView(n,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,TvUi.dp(this,62)));f.addView(u,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,TvUi.dp(this,62)));AlertDialog d=new AlertDialog.Builder(this).setTitle("添加配置源").setView(f).setNegativeButton("取消",null).setPositiveButton("导入",null).create();d.setOnShowListener(v->d.getButton(AlertDialog.BUTTON_POSITIVE).setOnClickListener(x->{try{TvServices.configurations.add(n.getText().toString(),u.getText().toString());d.dismiss();showSettings();}catch(Exception e){toast(msg(e));}}));d.show();}
private void showAccount(){LinearLayout root=page("电视设备登录","账户与同步");EditText server=TvUi.input(this,"https://你的同步域名");server.setText(TvServices.account.serverUrl());Button code=TvUi.button(this,"获取电视登录码",true),both=TvUi.button(this,"双向同步",true),upload=TvUi.button(this,"上传本地数据",false),download=TvUi.button(this,"下载云端数据",false),logout=TvUi.button(this,"退出登录",false);TextView status=TvUi.text(this,TvServices.account.signedIn()?"电视已登录，可选择同步方向。":"游客模式：本地播放可用，但不进行同步。");root.addView(server,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,TvUi.dp(this,64)));root.addView(code,new LinearLayout.LayoutParams(TvUi.dp(this,300),TvUi.dp(this,64)));root.addView(status,TvUi.matchWrap());LinearLayout actions=new LinearLayout(this);actions.addView(both,new LinearLayout.LayoutParams(TvUi.dp(this,220),TvUi.dp(this,60)));actions.addView(upload,new LinearLayout.LayoutParams(TvUi.dp(this,240),TvUi.dp(this,60)));actions.addView(download,new LinearLayout.LayoutParams(TvUi.dp(this,240),TvUi.dp(this,60)));root.addView(actions,TvUi.matchWrap());root.addView(logout,new LinearLayout.LayoutParams(TvUi.dp(this,240),TvUi.dp(this,60)));setPage(root);code.setOnClickListener(v->{try{TvServices.account.bind(server.getText().toString());}catch(Exception e){status.setText(msg(e));return;}status.setText("正在获取设备码…");executor.execute(()->{try{AccountClient.TvCode c=TvServices.account.beginTvLogin("MT播放器");runOnUiThread(()->{status.setText("请在手机或电脑打开：\n"+c.verificationUri+"\n\n输入确认码：  "+c.userCode+"\n\n等待确认中…");poll(c,status);});}catch(Exception e){runOnUiThread(()->status.setText("获取失败："+msg(e)));}});});both.setOnClickListener(v->runSync(status,0));upload.setOnClickListener(v->runSync(status,1));download.setOnClickListener(v->runSync(status,2));logout.setOnClickListener(v->{TvServices.account.logout();status.setText("已退出登录，本地数据仍然保留。");});}
private void runSync(TextView status,int mode){status.setText(mode==1?"正在上传本地数据…":mode==2?"正在下载云端数据…":"正在双向同步…");executor.execute(()->{try{AndroidSyncService.Result result=mode==1?TvServices.sync.upload():mode==2?TvServices.sync.download():TvServices.sync.synchronize();runOnUiThread(()->status.setText("同步完成：上传 "+result.pushed+" 项，下载 "+result.pulled+" 项。"));}catch(Exception e){runOnUiThread(()->status.setText("同步失败："+msg(e)));}});}
private void poll(AccountClient.TvCode c,TextView status){handler.postDelayed(()->executor.execute(()->{try{boolean ok=TvServices.account.pollTvLogin(c.deviceCode);runOnUiThread(()->{if(ok){status.setText("登录成功，正在下载云端数据与会员推送…");runSync(status,2);}else poll(c,status);});}catch(Exception e){runOnUiThread(()->status.setText("登录码已失效，请重新获取。"));}}),Math.max(5,c.pollIntervalSeconds)*1000L);}
private void showAbout(){ScrollView scroll=new ScrollView(this);LinearLayout root=page("关于软件","MT播放器 TV · 1.3.1");root.addView(TvUi.text(this,"原生 Android TV 客户端 · Android 5.0 及以上\n\n源码仓库：https://github.com/meiyemeng/MTplayer\n客户端下载：https://github.com/meiyemeng/MTplayer/releases/latest\n\n软件不预置、不存储、不上传、不分发任何影视内容，仅播放用户自行配置且有权访问的媒体。"),TvUi.matchWrap());root.addView(TvUi.title(this,"支持项目",22),TvUi.matchWrap());ImageView donate=new ImageView(this);donate.setScaleType(ImageView.ScaleType.CENTER_INSIDE);Glide.with(this).load(R.drawable.alipay_donate).into(donate);root.addView(donate,new LinearLayout.LayoutParams(TvUi.dp(this,320),TvUi.dp(this,470)));root.addView(TvUi.text(this,"支付宝扫码为自愿捐助，不解锁内容或会员权益。"),TvUi.matchWrap());scroll.addView(root);setPage(scroll);}
private void open(MediaItem i){Intent x=new Intent(this,TvDetailActivity.class);x.putExtra("item",i);startActivity(x);}private void toast(String s){Toast.makeText(this,s,Toast.LENGTH_LONG).show();}private static String msg(Throwable e){return e.getMessage()==null?e.getClass().getSimpleName():e.getMessage();}private static String safe(String s){return s==null?"":s;}private static boolean isHttpAddress(String value){try{java.net.URI uri=java.net.URI.create(value);return uri.getHost()!=null&&("http".equalsIgnoreCase(uri.getScheme())||"https".equalsIgnoreCase(uri.getScheme()));}catch(RuntimeException ex){return false;}}}
